    10→// Helper to create a minimal valid Gallops structure
    11→fn make_valid_gallops() -> jjrg_Gallops {
    12→    jjrg_Gallops {
    13→        next_heat_seed: "AB".to_string(),
    14→        heats: IndexMap::new(),
    15→    }
    16→}
    17→
    18→// Helper to create a valid Tack
    19→fn make_valid_tack(state: jjrg_PaceState, silks: &str) -> jjrg_Tack {
    20→    jjrg_Tack {
    21→        ts: "260101-1200".to_string(),
    22→        state,
    23→        text: "Test tack text".to_string(),
    24→        silks: silks.to_string(),
    25→        basis: JJRG_UNKNOWN_BASIS.to_string(),
    26→        direction: None,
    27→    }
    28→}
    29→
    30→// Helper to create a valid Pace
    31→fn make_valid_pace(heat_id: &str) -> (String, jjrg_Pace) {
    32→    let pace_key = format!("₢{}AAA", heat_id);
    33→    let pace = jjrg_Pace {
    34→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "test-pace")],
    35→    };
    36→    (pace_key, pace)
    37→}
    38→
    39→// Helper to create a valid Heat
    40→fn make_valid_heat(heat_id: &str, silks: &str, status: jjrg_HeatStatus) -> (String, jjrg_Heat) {
    41→    let heat_key = format!("₣{}", heat_id);
    42→    let (pace_key, pace) = make_valid_pace(heat_id);
    43→    let mut paces = BTreeMap::new();
    44→    paces.insert(pace_key.clone(), pace);
    45→
    46→    let heat = jjrg_Heat {
    47→        silks: silks.to_string(),
    48→        creation_time: "260101".to_string(),
    49→        status,
    50→        order: vec![pace_key],
    51→        next_pace_seed: "AAB".to_string(),
    52→        paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
    53→        paces,
    54→    };
    55→    (heat_key, heat)
    56→}
