   282→#[test]
   283→fn jjtfu_racing_moves_heat_to_front() {
   284→    let mut gallops = make_valid_gallops();
   285→
   286→    // Create three heats with valid base64 firemarks (A-Z, a-z, 0-9, -, _)
   287→    let (key_ab, heat_ab) = make_valid_heat("AB", "first-heat", jjrg_HeatStatus::Stabled);
   288→    let (key_cd, heat_cd) = make_valid_heat("CD", "second-heat", jjrg_HeatStatus::Stabled); // Note: start as Stabled
   289→    let (key_ef, heat_ef) = make_valid_heat("EF", "third-heat", jjrg_HeatStatus::Stabled);
   290→
   291→    gallops.heats.insert(key_ab.clone(), heat_ab);
   292→    gallops.heats.insert(key_cd.clone(), heat_cd);
   293→    gallops.heats.insert(key_ef.clone(), heat_ef);
   294→
   295→    // Move second heat (CD) to racing - should move to front
   296→    let args = jjrg_FurloughArgs {
   297→        firemark: "CD".to_string(),
   298→        racing: true,
   299→        stabled: false,
   300→        silks: None,
   301→    };
   302→
   303→    let result = gallops.jjrg_furlough(args);
   304→    assert!(result.is_ok(), "Furlough failed: {:?}", result);
   305→
   306→    // Verify ordering: CD should be first now
   307→    let keys: Vec<_> = gallops.heats.keys().collect();
   308→    assert_eq!(*keys[0], key_cd, "Heat CD should be moved to front");
   309→}
