   474→#[test]
   475→fn jjtg_slate_creates_pace() {
   476→    let mut gallops = make_valid_gallops();
   477→    let (heat_key, heat) = make_valid_heat("AB", "my-heat");
   478→    gallops.heats.insert(heat_key.clone(), heat);
   479→
   480→    let args = jjrg_SlateArgs {
   481→        firemark: "AB".to_string(),
   482→        silks: "test-pace".to_string(),
   483→        text: "Do something useful".to_string(),
   484→        before: None,
   485→        after: None,
   486→        first: false,
   487→    };
   488→
   489→    let result = gallops.jjrg_slate(args).unwrap();
   490→
   491→    // Check result
   492→    assert!(result.coronet.starts_with('₢'));
   493→    assert!(result.coronet.contains("AB")); // Embeds heat identity
   494→
   495→    // Check pace was created
   496→    let heat = gallops.heats.get(&heat_key).unwrap();
   497→    assert!(heat.paces.contains_key(&result.coronet));
   498→    let pace = heat.paces.get(&result.coronet).unwrap();
   499→    assert_eq!(pace.tacks.len(), 1);
   500→    assert_eq!(pace.tacks[0].silks, "test-pace");
   501→    assert_eq!(pace.tacks[0].state, jjrg_PaceState::Rough);
   502→    assert_eq!(pace.tacks[0].text, "Do something useful");
   503→
   504→    // Check order was updated
   505→    assert!(heat.order.contains(&result.coronet));
   506→
   507→    // Check seed was incremented (was AAB, now AAC due to existing pace)
   508→    assert_eq!(heat.next_pace_seed, "AAC");
   509→}
